"use client";

import { useState } from "react";
import { DataTable, Column } from "@/components/tables/data-table";
import {
  useUsers,
  useActivateUser,
  useDeactivateUser,
} from "@/hooks/use-users";
import type { User } from "@/types";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import {
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
  SheetDescription,
} from "@/components/ui/sheet";
import { Separator } from "@/components/ui/separator";
import { MoreHorizontal, UserCheck, UserX, Eye, Users } from "lucide-react";
import { formatDate } from "@/lib/utils";

export default function UsersPage() {
  const [page, setPage] = useState(1);
  const [selectedUser, setSelectedUser] = useState<User | null>(null);

  const { data, isLoading } = useUsers({ page });
  const activate = useActivateUser();
  const deactivate = useDeactivateUser();

  const columns: Column<User>[] = [
    {
      key: "fullName",
      header: "User",
      cell: (user) => {
        const initials = user.fullName
          ?.split(" ")
          .map((n: string) => n[0])
          .join("")
          .slice(0, 2)
          .toUpperCase();
        return (
          <div className="flex items-center gap-3">
            <Avatar className="h-8 w-8">
              <AvatarImage src={user.profileImage?.url} />
              <AvatarFallback className="bg-blue-100 text-blue-700 text-xs font-semibold">
                {initials}
              </AvatarFallback>
            </Avatar>
            <div>
              <p className="font-medium text-sm">{user.fullName}</p>
              <p className="text-xs text-muted-foreground">{user.email}</p>
            </div>
          </div>
        );
      },
    },
    {
      key: "role",
      header: "Role",
      cell: (user) => {
        const role = user.role?.name ?? "user";
        const variants: Record<string, "default" | "destructive" | "secondary" | "outline"> = {
          "super-admin": "destructive",
          admin: "default",
          moderator: "secondary",
          business: "outline",
          user: "outline",
        };
        return <Badge variant={variants[role] ?? "outline"}>{role}</Badge>;
      },
    },
    {
      key: "isActive",
      header: "Status",
      cell: (user) => (
        <Badge variant={user.isActive ? "success" : "destructive"}>
          {user.isActive ? "Active" : "Inactive"}
        </Badge>
      ),
    },
    {
      key: "isPro",
      header: "Plan",
      cell: (user) => (
        <Badge variant={user.isPro ? "default" : "outline"}>
          {user.isPro ? "Pro" : "Free"}
        </Badge>
      ),
    },
    {
      key: "createdAt",
      header: "Joined",
      cell: (user) => (
        <span className="text-sm text-muted-foreground">
          {formatDate(user.createdAt)}
        </span>
      ),
    },
    {
      key: "actions",
      header: "",
      cell: (user) => (
        <DropdownMenu>
          <DropdownMenuTrigger asChild>
            <Button variant="ghost" size="icon" className="h-8 w-8">
              <MoreHorizontal className="h-4 w-4" />
            </Button>
          </DropdownMenuTrigger>
          <DropdownMenuContent align="end">
            <DropdownMenuItem onClick={() => setSelectedUser(user)}>
              <Eye className="mr-2 h-4 w-4" />
              View Details
            </DropdownMenuItem>
            {user.isActive ? (
              <DropdownMenuItem
                className="text-red-600 focus:text-red-600"
                onClick={() => deactivate.mutate(user.id)}
              >
                <UserX className="mr-2 h-4 w-4" />
                Deactivate
              </DropdownMenuItem>
            ) : (
              <DropdownMenuItem
                className="text-green-600 focus:text-green-600"
                onClick={() => activate.mutate(user.id)}
              >
                <UserCheck className="mr-2 h-4 w-4" />
                Activate
              </DropdownMenuItem>
            )}
          </DropdownMenuContent>
        </DropdownMenu>
      ),
    },
  ];

  return (
    <div className="space-y-6">
      <div className="flex items-center gap-3">
        <div className="p-2 rounded-lg bg-blue-100">
          <Users className="h-5 w-5 text-blue-600" />
        </div>
        <div>
          <h1 className="text-2xl font-bold">Users</h1>
          <p className="text-muted-foreground text-sm">
            Manage user accounts and permissions
            {data?.total ? ` · ${data.total} total` : ""}
          </p>
        </div>
      </div>

      <DataTable
        columns={columns}
        data={(data?.data ?? []) as User[]}
        isLoading={isLoading}
        searchKey="fullName"
        searchPlaceholder="Search by name..."
        page={page}
        totalPages={data?.totalPages}
        onPageChange={setPage}
      />

      {/* User Detail Drawer */}
      <Sheet open={!!selectedUser} onOpenChange={() => setSelectedUser(null)}>
        <SheetContent className="w-full sm:max-w-md overflow-y-auto">
          <SheetHeader>
            <SheetTitle>User Details</SheetTitle>
            <SheetDescription>Full profile information</SheetDescription>
          </SheetHeader>

          {selectedUser && (
            <div className="mt-6 space-y-6">
              <div className="flex items-center gap-4">
                <Avatar className="h-16 w-16">
                  <AvatarImage src={selectedUser.profileImage?.url} />
                  <AvatarFallback className="bg-blue-100 text-blue-700 text-xl font-bold">
                    {selectedUser.fullName
                      ?.split(" ")
                      .map((n: string) => n[0])
                      .join("")
                      .slice(0, 2)
                      .toUpperCase()}
                  </AvatarFallback>
                </Avatar>
                <div>
                  <h3 className="text-lg font-semibold">{selectedUser.fullName}</h3>
                  <p className="text-muted-foreground text-sm">{selectedUser.email}</p>
                  <div className="flex gap-2 mt-1">
                    <Badge variant={selectedUser.isActive ? "success" : "destructive"}>
                      {selectedUser.isActive ? "Active" : "Inactive"}
                    </Badge>
                    {selectedUser.isPro && <Badge>Pro</Badge>}
                  </div>
                </div>
              </div>

              <Separator />

              <div className="grid grid-cols-2 gap-4 text-sm">
                <div>
                  <p className="text-muted-foreground font-medium">Role</p>
                  <p className="capitalize">{selectedUser.role?.name ?? "user"}</p>
                </div>
                <div>
                  <p className="text-muted-foreground font-medium">Phone</p>
                  <p>{selectedUser.phone ?? "—"}</p>
                </div>
                <div>
                  <p className="text-muted-foreground font-medium">Joined</p>
                  <p>{formatDate(selectedUser.createdAt)}</p>
                </div>
                <div>
                  <p className="text-muted-foreground font-medium">Website</p>
                  <p className="truncate">{selectedUser.website ?? "—"}</p>
                </div>
                {selectedUser.deactivatedAt && (
                  <div className="col-span-2">
                    <p className="text-muted-foreground font-medium">Deactivated</p>
                    <p className="text-red-600">{formatDate(selectedUser.deactivatedAt)}</p>
                  </div>
                )}
              </div>

              {selectedUser.description && (
                <>
                  <Separator />
                  <div>
                    <p className="text-muted-foreground font-medium text-sm mb-1">Bio</p>
                    <p className="text-sm">{selectedUser.description}</p>
                  </div>
                </>
              )}

              <Separator />
              <div className="flex gap-2">
                {selectedUser.isActive ? (
                  <Button
                    variant="destructive"
                    size="sm"
                    className="flex-1"
                    onClick={() => {
                      deactivate.mutate(selectedUser.id);
                      setSelectedUser(null);
                    }}
                  >
                    <UserX className="mr-2 h-4 w-4" />
                    Deactivate User
                  </Button>
                ) : (
                  <Button
                    size="sm"
                    className="flex-1"
                    onClick={() => {
                      activate.mutate(selectedUser.id);
                      setSelectedUser(null);
                    }}
                  >
                    <UserCheck className="mr-2 h-4 w-4" />
                    Activate User
                  </Button>
                )}
              </div>
            </div>
          )}
        </SheetContent>
      </Sheet>
    </div>
  );
}
